#!/usr/bin/env python3\nimport paramiko\nimport time\n\nHOST = "168.119.79.238"\nPORT = 77\nUSERNAME = "sanliur"\nPASSWORD = "CHANGE_ME_CWP_SSH_PASSWORD"\nSUDO_PASS = "CHANGE_ME_CWP_SSH_PASSWORD"\n\ndef main():\n    ssh = paramiko.SSHClient()\n    ssh.set_missing_host_key_policy(paramiko.AutoAddPolicy())\n    ssh.connect(HOST, port=PORT, username=USERNAME, password=PASSWORD, \n                timeout=20, look_for_keys=False, allow_agent=False)\n    \n    channel = ssh.invoke_shell()\n    time.sleep(2)\n    \n    print("Fixing PostgreSQL with sudo...")\n    \n    # Fix pg_hba.conf with sudo\n    channel.send("sudo sed -i 's/scram-sha-256/trust/g' /var/lib/pgsql/data/pg_hba.conf\n")\n    time.sleep(2)\n    channel.send(SUDO_PASS + "\n")\n    time.sleep(2)\n    \n    channel.send("sudo sed -i 's/ident/trust/g' /var/lib/pgsql/data/pg_hba.conf\n")\n    time.sleep(2)\n    channel.send(SUDO_PASS + "\n")\n    time.sleep(2)\n    \n    channel.send("sudo sed -i 's/md5/trust/g' /var/lib/pgsql/data/pg_hba.conf\n")\n    time.sleep(2)\n    channel.send(SUDO_PASS + "\n")\n    time.sleep(2)\n    \n    channel.send("sudo systemctl restart postgresql\n")\n    time.sleep(2)\n    channel.send(SUDO_PASS + "\n")\n    time.sleep(5)\n    \n    # Test DB\n    channel.send("psql -U sanliur_sanliurfa -d sanliur_sanliurfa -h localhost -c 'SELECT 1'\n")\n    time.sleep(3)\n    \n    output = ""\n    while channel.recv_ready():\n        output += channel.recv(4096).decode('utf-8', errors='ignore')\n        time.sleep(1)\n    \n    print("OUTPUT:")\n    print(output[-600:])\n    \n    # Restart app\n    channel.send("source ~/.nvm/nvm.sh && pm2 restart sanliurfa\n")\n    time.sleep(5)\n    \n    # Test site\n    channel.send("curl -s http://127.0.0.1:4321/ | head -1\n")\n    time.sleep(2)\n    \n    output2 = ""\n    while channel.recv_ready():\n        output2 += channel.recv(4096).decode('utf-8', errors='ignore')\n        time.sleep(1)\n    \n    print("\nSITE TEST:")\n    print(output2[-300:])\n    \n    channel.close()\n    ssh.close()\n\nif __name__ == "__main__":\n    main()\n
